var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"찾았다, 늙다리!","JPN":"見つけたぞ、ジジイ！","ENG":"Finally found ya, old man!","TWN":"找到了，老頭！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"오, 이런. 젊은이께서 날 보겠다고 서둘러 달려와 주다니. 의외로군.","JPN":"おっと。若者が私に会おうと急いで駆けつけてくれるとはな。意外だ。","ENG":"My, my. It’s not every day that a young man comes rushing to see me.","TWN":"喔，哎呀，年輕人為了見我，竟然急著趕來了，真意外啊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"약속 장소에 나타날 때는 좀 더 여유로운 모습으로 들어오시죠, 물벼룩.","JPN":"待ち合わせ場所に現れる時は、もう少し余裕のある姿で入ってきなさい、ミジンコ。","ENG":"The next time you show up at the meeting place, try not to rush in, Water Flea.","TWN":"出現在約定地點的時候，用更從容一點的姿態進來吧，水蚤。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 그게 중요해? 저 할아범 어디서 잡은 거야?","JPN":"今大事なのはそれじゃねぇだろ！　あのジジイ、どこで捕まえたんだよ。","ENG":"That’s not the point here! Where did you catch this guy?","TWN":"現在重點是這個嗎？那個老頭是在哪裡抓到的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이 공항에서 출국 심사를 받다가 체포됐어요.","JPN":"この空港で出国審査を受けている途中で逮捕されましたわ。","ENG":"He was arrested in the immigration office at this airport.","TWN":"在這個機場辦理出境審核的時候被逮捕的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"수배자로 등록되어 있는 걸 발견하고 직원이 체포했다더군요.","JPN":"指名手配犯に登録されているのを発見した職員が逮捕したらしいです。","ENG":"A worker there found him on the wanted list and arrested him.","TWN":"發現他是通緝者後，職員們就把他逮捕了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐어……?","JPN":"はあ……？","ENG":"Whaaaaaaaat...?","TWN":"什麼……？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"설마. 학회에서 제명된 셈이지.","JPN":"まさかとは思ったが。学会から除名されたわけだ。","ENG":"Well, well. I am basically expelled from the Society.","TWN":"恐怕，我算是被學會開除了吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이유는 짐작이 가네. LAKE-4 시설 탈환에 성공했다지?","JPN":"理由には心当たりがある。LAKE-4施設の奪還に成功したらしいな。","ENG":"I can guess why. They say they reclaimed LAKE-4.","TWN":"原因我也能猜到。你們成功奪回LAKE-4設施了？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양이 다른 길을 택했다면, 전혀 반대의 결과가 나왔겠지.","JPN":"マクレディーさんが他の道を選んでいたのなら、正反対の結果が出ただろう。","ENG":"If Ms. MacCready had chosen another path, the tables would have turned.","TWN":"如果麥克蕾蒂選擇了另一條路，應該會出現截然相反的結果吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"자부심을 가져도 좋아. 기관장의 덫은 멋지게 작동했어.","JPN":"誇ってもいいぞ。機関長の罠は見事働いたんだ。","ENG":"Have some pride in yourself. The trap worked marvelously.","TWN":"你可以驕傲。機關長的陷阱完美啟動了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회장 직위는 결국 맥크레디 양이 승계했고, 엘리시움 필하모닉은 심각한 타격을 받았지.","JPN":"学会長の座は結局マクレディーさんが受け継ぎ、エリシウムフィルハーモニーは深刻なダメージを負った。","ENG":"Ms. MacCready became President, and the Elysium Philharmonic was severely damaged.","TWN":"麥克蕾蒂最終繼承了學會長的職位，愛樂組織也受到了嚴重的打擊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"일석이조야. 시설에 있던 기관원들의 목숨 값으로는 충분한 결과지.","JPN":"一石二鳥だな。施設にいた機関員の命の対価としては十分な結果だ。","ENG":"Killing\xA0two\xA0birds\xA0with\xA0one\xA0stone. It’s definitely worth more than the casualties of the Institution at the facility.","TWN":"一箭雙雕。以設施裡機關成員的性命為代價，這樣的結果也值了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"어이, 영감! 뚫린 입이라고 뭘 멋대로 떠들어!","JPN":"おい、ジジイ！　何勝手にしゃべってんだよ！","ENG":"Hey! Don’t you dare start babbling nonsense with that old muzzle of yours!","TWN":"喂，老頭！你那張嘴給我注意點！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"폭력은 행사하지 마세요, 물벼룩. 재판에 고려될 수 있습니다.","JPN":"暴力は慎んでください、ミジンコ。裁判に影響がでます。","ENG":"Violence is prohibited at all cost, Water Flea. It will be noted in court.","TWN":"不要使用暴力，水蚤。審判時可能會被考慮進去。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"쳇……","JPN":"チッ……","ENG":"Sheesh...","TWN":"嘖……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이송하기 전에 몇 가지 묻죠, 제임스 교수.","JPN":"移送する前にいくつか質問いたします、ジェームス教授。","ENG":"Before we escort you over, may I have a word with you, Professor James?","TWN":"在移送之前，我想問你幾個問題，詹姆斯教授。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"질문은 언제나 환영이오. 당분간은 끈 떨어진 연 신세일 것 같으니.","JPN":"質問はいつでも歓迎だ。しばらくは寄る辺のない身で暇になるだろうからな。","ENG":"Questions are always welcome. I will be powerless for a while, anyway.","TWN":"歡迎隨時提問，反正我現在暫時失勢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"출국 후 목적지를 성황청이라고 했다더군요.","JPN":"出国後の目的地について、聖皇庁と答えたらしいですね。","ENG":"You said that your destination was Holy Curia.","TWN":"聽說你出國後的目的地是聖皇廳。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"신도 같지는 않은데, 그곳에는 무슨 일이죠?","JPN":"信徒には見えませんが、そちらにはなんの用ですか？","ENG":"You don’t strike me as a religious person... What were you planning to do there?","TWN":"你好像不是信徒，去那裡有什麼事嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"흠……","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"버넷 경과 나는 아주 오랜 친구였소.","JPN":"バーネット卿と私は古い友人だった。","ENG":"Sir Burnett and I were long friends.","TWN":"伯內特卿和我是老朋友。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그는 내가 내는 수수께끼를 매번 자신만의 방식으로 멋지게 풀어냈지.","JPN":"彼は私が出す謎を、いつも自分のやり方で見事解いみせた。","ENG":"He would always solve my puzzles in his own way.","TWN":"他每次都會用自己的方式，帥氣地解開我出的謎題。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그러다…… 성황청에서 발견된 파편을 두고 겨룰 때……","JPN":"そして……聖皇庁で発見された破片を巡り戦った時……","ENG":"Then... when we fought over the Fragment found in Holy Curia...","TWN":"然後……圍繞在聖皇廳發現的碎片展開較量時……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"우린 서로 마지막 수를 쓴 끝에 양측 다 중상을 입었지.","JPN":"私たちは最後の手を使ったあげく、二人とも重傷を負った。","ENG":"We were both gravely injured from a long and tiring fight.","TWN":"我們彼此都使出了最後一招，然後弄得兩敗俱傷。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그런데 정작, 파편의 행방은 묘연해졌어.","JPN":"ところで、いざ破片の行方はわからなくなっていた。","ENG":"However, it wasn't until later that we realized that the Fragment was nowhere to be found.","TWN":"可是，碎片的去向卻下落不明。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"겨우 최근에야 그 소재를 알게 되었지.","JPN":"それが最近になって、やっとその所在がわかったんだ。","ENG":"It was only recent that I came to hear the whereabouts of the Fragment.","TWN":"最近我好不容易才知道了其所在。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"젠장, 또 파편 타령이야?","JPN":"くっそ、また破片かよ？","ENG":"Shucks, not the Fragment again!","TWN":"可惡，又開始說碎片了？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회의 비호를 잃은 당신에게 파편이 의미가 있나요?","JPN":"学会の庇護を失ったあなたにとって、破片に何の意味があるのですか？","ENG":"Since you left the Society, what use would it have to you?","TWN":"對於失去了學會庇護的你來說，碎片還有意義嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"손에 넣는다고 해도 학회나, 저희에게 빼앗길 것은 자명한 일일 텐데요.","JPN":"手に入れたとしても、学会や私たちに奪われるのは火を見るよりも明らかでしょう。","ENG":"Even if you get your hands on it, it’s apparent that either we or the Society will take it away.","TWN":"就算你拿到手，明顯也會被學會或者我們搶走吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회는 늘 이름을 바꿔 가며 존속해 왔다네.","JPN":"学会は常に名を変えて存続してきた。","ENG":"The Society has been around for eons. Always changing names and concealing their identity.","TWN":"學會一直都是改換名稱存續的。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그 중에는 조직으로서 명맥을 이은 것도 있고, 새로운 단체가 이념을 계승한 사례도 있지.","JPN":"その中には組織として命脈を受け継いだのもあり、新しい団体が理念を継承した事例もある。","ENG":"Some kept their legacy in the form of organizations, while some adopted a new mindset.","TWN":"其中既有作為組織延續命脈的情況，也有新團體繼承理念的情況。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"변혁이 기다리는 시대이니, 새로운 학회가 나타나도 이상할 것 없지.","JPN":"変革を待っている時代だ、新しい学会が現れてもおかしくないだろう。","ENG":"It will be no surprise that a new Society will show up in an era full of change.","TWN":"如今是等待變革的時代，出現新的學會也不足為奇吧。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그리고 예상컨대 그 파편이……","JPN":"そして予想するに、その破片が……","ENG":"And if I may say so... that Fragment...","TWN":"而按照我預想，那個碎片……"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"새로운 구심점이 될 걸세.","JPN":"新しい核になるはずだ。","ENG":"...It will be a new pivot.","TWN":"就會成為新的核心。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"얘들아! 어서 뛰어!","JPN":"みんな！　早く走って！","ENG":"Guys! Run!","TWN":"大家快跑！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"보육원으로 가면 안 돼! 거긴 이미 침식체들 천지야!","JPN":"保育園に行っちゃダメ！　そこはもう侵食体だらけだよ！","ENG":"Don’t head towards the orphanage! It’s already packed with C.O.s there!","TWN":"不可以去育幼院！那裡全都是侵蝕體！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"……어? 어?","JPN":"……え？　え？","ENG":"H-huh…?","TWN":"……啊？啊？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"얘! 너 거기서 뭐 해! 가면 안 된다니까!","JPN":"ちょっと！　そこで何してるの！　行っちゃダメだって！","ENG":"Hey! What do you think you’re doing there? You can’t go that way!","TWN":"喂！你站在那幹什麼呢！不可以過去！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};